form:Form.form:Scripts:
		var GROUP_TREE;
var SCRIPT_ORIGINAL; 
var ID_ORIGINAL;
var SCRIPT_MODIFICADO="";

function RESULT()
{
	GROUP_TREE.SetSelectedId(Ctrl('hid_val').GetXValue());
	Ctrl("TREE_ID").SetXValue(Ctrl('hid_val').GetXValue());
	onClick();
}

function changes()
{
	SCRIPT_MODIFICADO = Ctrl("INFO").GetXValue();	
}   

function UNDO()
{
	Ctrl("INFO").SetXValue(SCRIPT_ORIGINAL);
}

function DEL()
{
	Ctrl("INFO").SetXValue('');
}

function SAVE()
{
	var MyITEM;
	var MyGROUP;
	var MyOBJ;
	var aux;
	var from;

	MyITEM =GROUP_TREE.GetItem(Ctrl("TREE_ID").GetXValue());
	MyGROUP=GROUP_TREE.GetGroup(Ctrl("TREE_ID").GetXValue());		

	MyOBJ=(MyITEM?MyITEM:MyGROUP);  

	if (MyOBJ)
	{
		var subtag=MyOBJ.Tag.split("&")[0];
		var esttag=MyOBJ.Tag.split("&")[1]; //id del elemento
		if(subtag=="root")
		{	
			var script  = Ctrl("INFO").GetXValue();
			if(script.length > 15600) 
			{
				alert("El texto supera los 15000. Por favor revise el contenido.");
				return false;
			}             
			else
			{                        
				Ctrl("desde").SetXValue(subtag);
				var script1 = script.substring(0,3900);
				var script2 = script.substring(3900,7800);
				var script3 = script.substring(7800,11700);
				var script4 = script.substring(11700,15600);
				Ctrl("script").SetXValue(script1);
				Ctrl("script1").SetXValue(script2);
				Ctrl("script2").SetXValue(script3);
				Ctrl("script3").SetXValue(script4);
			}
		}
		else
		{
			from   = subtag.split("-")[0]; //que se guarda -> fg: form-group; ff: form-field
			aux	   = subtag.split("-")[1]; 
			subtag = subtag.split("-")[2]; //script q se va a modificar -->onchange o onvalidate	
			if((from=="fg") || (from=="ff"))
			{
				Ctrl("desde").SetXValue(from);
				Ctrl("function").SetXValue(subtag);
				Ctrl("script").SetXValue(Ctrl("INFO").GetXValue());
				Ctrl("IdScript").SetXValue(esttag);
				if(from=="ff")
				{
					MySQL=GetProxy().SQLService().GetOBJ(Ctrl("main").getResource("qry:getIdParent"), '<DATA ID="'+esttag+'" />');
					Ctrl("IdParent").SetXValue(MySQL.IdParent);
				}
			}
			else
			{
				Ctrl("desde").SetXValue('');
				Ctrl("function").SetXValue('');
				Ctrl("script").SetXValue('');
				Ctrl("IdDesde").SetXValue('');
			}			
		}
	}
	Ctrl('main').DoEvent("SAVE");
}

function onClick()
{ 
	if(ID_ORIGINAL!=Ctrl("TREE_ID").GetXValue())
	{
		var MyITEM;
		var MyGROUP;
		var MyITEM_ORIGINAL;
		var MyGROUP_ORIGINAL;
		var MyOBJ;

		MyITEM =GROUP_TREE.GetItem(Ctrl("TREE_ID").GetXValue());
		MyGROUP=GROUP_TREE.GetGroup(Ctrl("TREE_ID").GetXValue());

		MyITEM_ORIGINAL =GROUP_TREE.GetItem(ID_ORIGINAL);
		MyGROUP_ORIGINAL=GROUP_TREE.GetGroup(ID_ORIGINAL);

		MyOBJ=(MyITEM?MyITEM:MyGROUP);
		if (MyOBJ)
		{   
			var subtag=MyOBJ.Tag.split("&")[0];
			var esttag=MyOBJ.Tag.split("&")[1];

			var aux;
			var from;

			aux	   = subtag.split("-")[1];
			from   = subtag.split("-")[0];
			subtag = subtag.split("-")[2];		
			if(MyOBJ.Tag.split("&")[0]=="root")
				aux = "script";

			if(aux=="script")
			{          
				CtrlEnabled('INFO', true);
				if(subtag=="onChange")
					MySQL=GetProxy().SQLService().GetOBJ(Ctrl("main").getResource("sql:"+subtag), '<DATA ID="'+esttag+'" from="'+from+'" />');
				if(subtag=="onValidate")
					MySQL=GetProxy().SQLService().GetOBJ(Ctrl("main").getResource("sql:"+subtag), '<DATA ID="'+esttag+'" from="'+from+'" />');
				if(MyOBJ.Tag.split("&")[0]=="root")
					MySQL=GetProxy().SQLService().GetOBJ(Ctrl("main").getResource("sql:root"), '<DATA ID="'+Ctrl("IdForm").GetXValue()+'" />');						
			}
		}     
		if(aux=="script")
		{ 
			if((SCRIPT_ORIGINAL != SCRIPT_MODIFICADO) && (SCRIPT_MODIFICADO!=""))
	  	{            
	  	  if(confirm('Se realizaron cambios en el script de funciones, ¿Desea continuar y perder los cambios?'))
		  	{
					if(MySQL.result == "0")
						Ctrl("INFO").SetXValue('');
					else	
						Ctrl("INFO").SetXValue(MySQL.result);
					SCRIPT_ORIGINAL   = Ctrl("INFO").GetXValue();
					ID_ORIGINAL				= Ctrl("TREE_ID").GetXValue();
					SCRIPT_MODIFICADO = "";	
				}
				else
				{                         
					if(MyITEM_ORIGINAL!=null)
						GROUP_TREE.ClickItem(ID_ORIGINAL);
					if(MyGROUP_ORIGINAL!=null)
						GROUP_TREE.ClickGroup(ID_ORIGINAL);					
				}
			}
			else
			{
				if(MySQL.result == "0")
					Ctrl("INFO").SetXValue('');
				else	
					Ctrl("INFO").SetXValue(MySQL.result);
				SCRIPT_ORIGINAL   = Ctrl("INFO").GetXValue();
				ID_ORIGINAL				= Ctrl("TREE_ID").GetXValue();
				SCRIPT_MODIFICADO = "";		
			}			
		}
		else
		{         
			if((SCRIPT_ORIGINAL != SCRIPT_MODIFICADO) && (SCRIPT_MODIFICADO!=""))
	  	{
		  	if (confirm('Se realizaron cambios en el script de funciones, ¿Desea continuar y perder los cambios?')) 
		  	{
					Ctrl("INFO").SetXValue("**Sin información adicional.**");
					CtrlEnabled('INFO', false);
					SCRIPT_ORIGINAL   = Ctrl("INFO").GetXValue();
					ID_ORIGINAL				= Ctrl("TREE_ID").GetXValue();
					SCRIPT_MODIFICADO = "";	
				}
				else
				{        
					if(MyITEM_ORIGINAL!=null)
						GROUP_TREE.ClickItem(ID_ORIGINAL);
					if(MyGROUP_ORIGINAL!=null)
						GROUP_TREE.ClickGroup(ID_ORIGINAL);
				}
			}		
		}
	}		
}


function LoadChilds(objTree, objGroup)
{                                    
	var subtag=objGroup.Tag.split("&")[0];
	switch (subtag)
	{
		case "root":
			objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:form-root"), ""));
		break;

		case "groups":
			objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:form-groups"), '<DATA ID="'+Ctrl("IdForm").GetXValue()+'" />'));
		break;

		case "form-groups":
			objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:form-groups-script"), '<DATA ID="'+objGroup.Id+'" />'));
		break;

		case "form-groupsfields":
			objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:form-fields"), '<DATA ID="'+objGroup.Tag.split("&")[1]+'" />'));
		break;

		case "form-fields":
		  objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:form-fields-script"), '<DATA ID="'+objGroup.Id+'" mode="'+objGroup.Tag.split("&")[1]+'" />'));
		break;

		default:
			//alert("LoadChilds:"+objGroup.Tag+" - "+objGroup.Id);
		break;
	}

}

function OnLoad()
{
	np = new NomadProxy("", ut);
	nSQL = np.SQLService();
	SCRIPT_ORIGINAL="";
	SCRIPT_MODIFICADO="";
	GROUP_TREE=clsClientTree("CONT_FORM_TREE","TREE_ID","CLOCK.ico","folder.ico","folder-close.ico","item.ico",true,LoadChilds,null,onClick);	
	//Cargo los formularios            
	GROUP_TREE.SetXML(null, '<tree><group id="." label="Funciones" imgOpen="cabinet.ico" imgClose="cabinet-close.ico" tag="root" /><group id="*" label="Grupos" imgOpen="cabinet.ico" imgClose="cabinet-close.ico" tag="groups" /></tree>');                                                         
	GROUP_TREE.ClickExpGroup(".");     
	GROUP_TREE.ClickGroup(".");
	ID_ORIGINAL = Ctrl("TREE_ID").GetXValue();        	
}
